<?php defined('ABSPATH') || exit; class FounderKit_Ajax { private static ?FounderKit_Ajax $instance=null; public static function instance(): self { if(!self::$instance) self::$instance=new self(); return self::$instance; } public function __construct(){ add_action('wp_ajax_founderkit_action',[$this,'handle']); add_action('wp_ajax_nopriv_founderkit_action',[$this,'handle_public']); do_action('founderkit_ajax_init'); } private function check_rate_limit(): bool { $user_ip=sanitize_text_field($_SERVER['REMOTE_ADDR']??''); $transient_key='founderkit_rate_limit_'.md5($user_ip); $count=(int)get_transient($transient_key); if($count>=100){ return false; } set_transient($transient_key,$count+1,5*MINUTE_IN_SECONDS); return true; } public function handle_public(): void { if(!$this->check_rate_limit()){ wp_send_json_error(['message'=>__('Rate limit exceeded.','founderkit')],429); return; } do_action('founderkit_ajax_before_public_handle'); $fk_action=sanitize_text_field($_POST['fk_action']??''); if($fk_action==='load_more_posts'){ check_ajax_referer('founderkit_nonce','nonce',false); $this->load_more_posts(); return; } wp_send_json_error(['message'=>__('Permission denied.','founderkit')],403); } public function handle(): void { if(!$this->check_rate_limit()){ wp_send_json_error(['message'=>__('Rate limit exceeded.','founderkit')],429); return; } do_action('founderkit_ajax_before_handle'); check_ajax_referer('founderkit_nonce','nonce'); $fk_action=sanitize_text_field($_POST['fk_action']??''); $is_public_action=in_array($fk_action,['load_more_posts'],true); $allow_action=apply_filters('founderkit_ajax_user_permission',!$is_public_action||current_user_can('manage_founderkit'),$fk_action); if(!$allow_action){ wp_send_json_error(['message'=>__('Permission denied.','founderkit')],403); return; } if($fk_action==='toggle_block') $this->toggle_block(); elseif($fk_action==='save_settings') $this->save_settings(); elseif($fk_action==='load_more_posts') $this->load_more_posts(); elseif($fk_